parameters.jsCode:
// Anthropic's response text comes in as $json.content[0].text
const anthropicText = $json.content[0].text;

// Defensively strip markdown code fences if Claude included them
let cleaned = anthropicText.trim();
cleaned = cleaned.replace(/^```(?:json)?\s*\n?/i, '');
cleaned = cleaned.replace(/\n?\s*```\s*$/i, '');

// Parse with helpful error message if it fails
let analysis;
try {
  analysis = JSON.parse(cleaned);
} catch (error) {
  throw new Error(`Failed to parse JSON from Anthropic: ${error.message}\n\nText was:\n${anthropicText}`);
}

// Pull the original webhook data
const webhook = $('Webhook').item.json.body;

// Normalize sentiment to match HubSpot dropdown case (Capitalized)
const sentiment = analysis.caregiver_sentiment
  ? analysis.caregiver_sentiment.charAt(0).toUpperCase() + analysis.caregiver_sentiment.slice(1).toLowerCase()
  : '';

// Format risk signals: HubSpot multi-line text wants a string
const riskSignalsString = Array.isArray(analysis.risk_signals)
  ? analysis.risk_signals.join(', ')
  : (analysis.risk_signals || '');

// HTML-formatted risk signals list for the note
const riskSignalsHtml = Array.isArray(analysis.risk_signals)
  ? '<ul>' + analysis.risk_signals.map(s => `<li>${s}</li>`).join('') + '</ul>'
  : `<p>${analysis.risk_signals || 'None identified'}</p>`;

// Get today's date in YYYY-MM-DD format for HubSpot date picker
const today = new Date().toISOString().split('T')[0];

// Human-readable date for note title
const formattedDate = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

// Build the HTML note body (HubSpot notes render HTML)
const noteBody = `<p><strong>\ud83d\udcde Call Analysis &mdash; ${formattedDate}</strong></p>
<p><strong>Risk Score:</strong> ${analysis.risk_score}/10<br>
<strong>Caregiver Sentiment:</strong> ${sentiment}</p>
<p><strong>Summary:</strong><br>${analysis.summary}</p>
<p><strong>Risk Signals:</strong></p>${riskSignalsHtml}
<p><strong>Recommended Followup:</strong><br>${analysis.recommended_followup || 'None'}</p>
<hr>
<p><strong>Full Transcript:</strong></p>
<p>${webhook.transcript}</p>`;

// Build the complete HubSpot Note API payload (with association to the contact)
const notePayload = {
  properties: {
    hs_note_body: noteBody,
    hs_timestamp: new Date().toISOString()
  },
  associations: [
    {
      to: { id: webhook.contactId },
      types: [
        {
          associationCategory: 'HUBSPOT_DEFINED',
          associationTypeId: 202
        }
      ]
    }
  ]
};

// Return a clean, flat object for downstream nodes
return [{
  json: {
    contactID: webhook.contactId,
    transcript: webhook.transcript,
    summary: analysis.summary,
    risk_score: analysis.risk_score,
    caregiver_sentiment: sentiment,
    risk_signals: riskSignalsString,
    recommended_followup: analysis.recommended_followup || '',
    last_call_analyzed: today,
    notePayloadJson: JSON.stringify(notePayload)
  }
}];
